Here's the equivalent C code:

```c
#include <stdio.h>

int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    int temp = 1;
    while (m != n) {
        if (m % 10 == 0) {
            printf("0\n");
            return 0;
        }
        temp *= m;
        m -= 1;
    }
    printf("%d\n", temp % 10);
    return 0;
}
```

